            return False
    elif month in [4, 6, 9, 11]:
        if not (1 <= day <= 30):
            return False
    elif month == 2:
        # For simplicity, we are not checking for leap year as the rule states max 29 days for month 2.
        if not (1 <= day <= 29):
            return False
    else:
