def compare_one(a, b):
    """
    Create a function that takes integers, floats, or strings representing
    real numbers, and returns the larger variable in its given variable type.
    Return None if the values are equal.
    Note: If a real number is represented as a string, the floating point might be . or ,
    """

    def parse_number(x):
        if isinstance(x, (int, float)):
            return x
        elif isinstance(x, str):
            return float(x.replace(',', '.'))
        return None

    num_a = parse_number(a)
    num_b = parse_number(b)

    if num_a is None or num_b is None:
        return None

    if num_a == num_b:
        return None
    elif num_a > num_b:
        return a
    else:
        return b

def sum_squares(lst):
    """"
    This function will take a list of integers. For all entries in the list, the function shall square the integer entry if its index is a 
    multiple of 3 and will cube the integer entry if its index is a multiple of 4 and not a multiple of 3. The function will not 
    change the entries in the list whose indexes are not a multiple of 3 or 4. The function shall then return the sum of all entries. 

    Examples:
    For lst = [1,2,3] the output should be 6
    For lst = []  the output should be 0
    For lst = [-1,-5,2,-1,-5]  the output should be -126
    """
    if not lst:
        return 0

    modified_list = list(lst)  # Create a copy to avoid modifying the original list

    for i in range(len(modified_list)):
        if i % 3 == 0:
            modified_list[i] **= 2
        elif i % 4 == 0 and i % 3 != 0:
            modified_list[i] **= 3

    return sum(modified_list)

def x_or_y(n, x, y):
    """A simple program which should return the value of x if n is 
    a prime number and should return the value of y otherwise.

    Examples:
    for x_or_y(7, 34, 12) == 34
    for x_or_y(15, 8, 5) == 5

    """
    if n <= 1:
        return y

    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return y

    return x

def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    if not (1 <= number <= 1000):
        raise ValueError("Number must be between 1 and 1000")

    roman_map = {
        1000: 'm', 900: 'cm', 500: 'd', 400: 'cd', 100: 'c',
        90: 'xc', 50: 'l', 40: 'xl', 10: 'x', 9: 'ix', 5: 'v',
        4: 'iv', 1: 'i'
    }

    result = []
    for value, numeral in sorted(roman_map.items(), reverse=True):
        while number >= value:
            result.append(numeral)
            number -= value

    return "".join(result)

def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    has_letters = False
    for char in s:
        if char.isalpha():
            has_letters = True
            break

    if not has_letters:
        return s[::-1]
    else:
        result = []
        for char in s:
            if char.isalpha():
                if char.islower():
                    result.append(char.upper())
                else:
                    result.append(char.lower())
            else:
                result.append(char)
        return "".join(result)

import hashlib

def string_to_md5(text):
    """
    Given a string 'text', return its md5 hash equivalent string.
    If 'text' is an empty string, return None.

    >>> string_to_md5('Hello world') == '3e25960a79dbc69b674cd4ec67a72c62'
    """
    if not text:
        return None

    return hashlib.md5(text.encode('utf-8')).hexdigest()
